@implements IAsyncDisposable
@inject IAddressValidator AddressValidator

<fieldset disabled="@isValidating">
    <div>
        <label>Name</label>
        <input @bind="Shipping.Name" />
    </div>
    <div>
        <label>Address</label>
        <input @bind="Shipping.Address" />
    </div>
    <div>
        <label>City</label>
        <input @bind="Shipping.City" />
    </div>
    <div>
        <label>Zip Code</label>
        <input @bind="Shipping.ZipCode" />
    </div>
</fieldset>

@if (validationError is not null)
{
    <p class="validation-error">@validationError</p>
}

<button disabled="@isValidating" @onclick="HandleNext">
    @if (isValidating)
    {
        <span>Validating‚Ä¶</span>
    }
    else
    {
        <span>Next</span>
    }
</button>

@code {
    [Parameter, EditorRequired]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    private CancellationTokenSource? cts;
    private bool isValidating;
    private string? validationError;

    private async Task HandleNext()
    {
        // Cancel any in-flight validation (user changed fields and clicked again)
        cts?.Cancel();
        cts?.Dispose();
        cts = new CancellationTokenSource();
        var token = cts.Token;

        isValidating = true;
        validationError = null;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                Shipping.Address, Shipping.City, Shipping.ZipCode, token);

            if (isValid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                validationError = "The address could not be verified. Please check and try again.";
            }
        }
        catch (OperationCanceledException)
        {
            // Validation was cancelled ‚Äî either by a re-click or disposal. Nothing to do.
        }
        finally
        {
            isValidating = false;
        }
    }

    public ValueTask DisposeAsync()
    {
        cts?.Cancel();
        cts?.Dispose();
        return ValueTask.CompletedTask;
    }
}

